import{_ as i,C as o,o as s,c as l,E as n,w as r,a,a0 as d}from"./chunks/framework.CkNTPv-z.js";const v=JSON.parse('{"title":"Netherlands Legal Rights","description":"Legal rights for transgender people in the Netherlands","frontmatter":{"layout":"doc","title":"Netherlands Legal Rights","description":"Legal rights for transgender people in the Netherlands"},"headers":[],"relativePath":"europe/netherlands/legal-rights.md","filePath":"europe/netherlands/legal-rights.md","lastUpdated":null}'),h={name:"europe/netherlands/legal-rights.md"};function c(g,e,m,u,p,f){const t=o("Badge");return s(),l("div",null,[n(t,{variant:"yellow"},{default:r(()=>[...e[0]||(e[0]=[a("Self-ID since 2025",-1)])]),_:1}),n(t,{variant:"green"},{default:r(()=>[...e[1]||(e[1]=[a("Strong Anti-Discrimination Laws",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="legal-rights-in-the-netherlands" tabindex="-1">Legal Rights in the Netherlands <a class="header-anchor" href="#legal-rights-in-the-netherlands" aria-label="Permalink to &quot;Legal Rights in the Netherlands&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>The Netherlands transitioned to a self-determination model for legal gender recognition in 2025. Previously, the system required a medical expert statement and court approval (since 2014, when the sterilisation requirement was removed). The new law allows individuals aged 16 and over to change their legal gender marker through a simple administrative process at the municipality.</p><p>The current process:</p><ul><li>Declaration at the civil registry office (gemeente)</li><li>No medical documentation required</li><li>No surgery or diagnosis requirement</li><li>Minors aged 16-17 can apply with parental consent</li><li>A cooling-off period of several months previously required, now removed</li></ul><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><p>Name changes follow the gender recognition process. After changing the gender marker, the first name can be updated through the same municipal declaration. For name-only changes (without gender marker change), a separate application to the court is required.</p><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>The Netherlands has strong anti-discrimination legislation:</p><ul><li><strong>Equal Treatment Act (Algemene wet gelijke behandeling)</strong> — Prohibits discrimination based on gender, which includes gender identity</li><li><strong>Employment</strong> — Protection from hiring discrimination to termination</li><li><strong>Healthcare</strong> — Right to access gender affirming care</li><li><strong>Education</strong> — Protection in schools and universities</li><li><strong>Housing and goods/services</strong> — Full protection</li></ul><p>The <strong>Netherlands Institute for Human Rights (College voor de Rechten van de Mens)</strong> handles discrimination complaints.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>The Dutch Penal Code (Wetboek van Strafrecht) includes discrimination as an aggravating circumstance for crimes. Article 137c-137g prohibits:</p><ul><li>Defamation based on protected characteristics</li><li>Incitement to hatred and discrimination</li><li>Violence with discriminatory motives</li></ul><p>Gender identity is explicitly covered under these provisions.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Transgender Network Nederland</strong> — <a href="https://www.transgendernetwerk.nl/" target="_blank" rel="noreferrer">transgendernetwerk.nl</a></li><li><strong>COC Nederland</strong> — LGBT rights organisation: <a href="https://www.coc.nl/" target="_blank" rel="noreferrer">coc.nl</a></li><li><strong>College voor de Rechten van de Mens</strong> — <a href="https://www.mensenrechten.nl/" target="_blank" rel="noreferrer">mensenrechten.nl</a></li><li><strong>Rijksoverheid</strong> — Government information: <a href="https://www.rijksoverheid.nl/" target="_blank" rel="noreferrer">rijksoverheid.nl</a></li></ul>',17))])}const _=i(h,[["render",c]]);export{v as __pageData,_ as default};
